import{_ as o,o as t,c as a,a as d}from"./chunks/plugin-vue_export-helper.B0FdOn3A.js";const h=JSON.parse('{"title":"CLAUDE.md — alterfo.github.io-src","description":"","frontmatter":{},"headers":[],"relativePath":"CLAUDE.md","filePath":"CLAUDE.md"}'),r={name:"CLAUDE.md"};function i(l,e,c,s,n,p){return t(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="claude-md-—-alterfo-github-io-src" tabindex="-1">CLAUDE.md — alterfo.github.io-src <a class="header-anchor" href="#claude-md-—-alterfo-github-io-src" aria-label="Permalink to &quot;CLAUDE.md — alterfo.github.io-src&quot;">​</a></h1><h2 id="project-overview" tabindex="-1">Project overview <a class="header-anchor" href="#project-overview" aria-label="Permalink to &quot;Project overview&quot;">​</a></h2><p>VitePress-based personal site with three fully client-side apps:</p><ul><li><code>/idef0</code> — IDEF0 diagram editor (SVG + Vue 3, FIPS 183)</li><li><code>/journal</code> — private encrypted daily journal (WebCrypto AES-GCM, IndexedDB, 500-words/day mechanic, file-based sync)</li><li><code>/piano</code> — interactive MIDI piano teacher (Web MIDI API, VexFlow notation, IndexedDB progress)</li></ul><h2 id="key-paths" tabindex="-1">Key paths <a class="header-anchor" href="#key-paths" aria-label="Permalink to &quot;Key paths&quot;">​</a></h2><ul><li><code>.vitepress/theme/components/IDEF0Editor.vue</code> — root Vue component wrapped in <code>&lt;ClientOnly&gt;</code>, SVG-based editor</li><li><code>.vitepress/theme/components/IDEF0Editor/</code> — editor modules (see below)</li><li><code>idef0.md</code> — page that mounts the editor</li><li><code>.vitepress/theme/components/crypto.js</code> — shared WebCrypto substrate (PBKDF2 → AES-GCM); reused by journal and future modules</li><li><code>.vitepress/theme/components/Journal.vue</code> — journal root component (<code>&lt;ClientOnly&gt;</code>): unlock screen, editor, sync UI</li><li><code>.vitepress/theme/components/Journal/</code> — journal modules (see below)</li><li><code>journal.md</code> — page that mounts the journal (<code>layout: false</code>)</li><li><code>.vitepress/theme/components/Piano.vue</code> — piano teacher root component (async/<code>&lt;ClientOnly&gt;</code>): topbar, stave, keyboard, metronome</li><li><code>.vitepress/theme/components/Piano/</code> — piano modules (see below)</li><li><code>piano.md</code> — page that mounts the piano teacher</li></ul><h2 id="idef0-editor-modules" tabindex="-1">IDEF0 Editor modules <a class="header-anchor" href="#idef0-editor-modules" aria-label="Permalink to &quot;IDEF0 Editor modules&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>model.js</code></td><td>Reactive project/diagram/box/arrow state via Vue 3 <code>ref</code>/<code>reactive</code>; CRUD functions</td></tr><tr><td><code>renderer.js</code></td><td>Pure functions → SVG attribute objects for boxes, arrows (Manhattan routing), boundary arrows, labels</td></tr><tr><td><code>layout.js</code></td><td><code>autoLayout</code> (FIPS 183 diagonal placement), <code>fitToView</code> for zoom/pan</td></tr><tr><td><code>icom.js</code></td><td>ICOM type constants, <code>SIDE_FOR_TYPE</code>, <code>icomCode()</code>, <code>validateDiagram()</code> (FIPS 183 rules)</td></tr><tr><td><code>history.js</code></td><td>Snapshot-based undo/redo (50-step limit); resets on diagram navigation</td></tr><tr><td><code>hierarchy.js</code></td><td><code>decomposeBox</code>, node-id scheme (A0→A1→A11…), breadcrumb, <code>navigateTo</code>, <code>navigateUp</code></td></tr><tr><td><code>db.js</code></td><td>IndexedDB persistence (<code>loadProject</code> / <code>saveProject</code>, debounce 300 ms) + cross-tab sync via localStorage</td></tr><tr><td><code>exporter.js</code></td><td><code>exportToSVG</code>, <code>exportToPNG</code> (2×), <code>exportToJSON</code>, <code>importFromJSON</code></td></tr></tbody></table><h2 id="fips-183-icom-arrow-rules" tabindex="-1">FIPS 183 ICOM arrow rules <a class="header-anchor" href="#fips-183-icom-arrow-rules" aria-label="Permalink to &quot;FIPS 183 ICOM arrow rules&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Edge</th><th>Marker</th></tr></thead><tbody><tr><td>INPUT</td><td>left (enters block)</td><td>I</td></tr><tr><td>OUTPUT</td><td>right (exits block)</td><td>O</td></tr><tr><td>CONTROL</td><td>top (enters block)</td><td>C</td></tr><tr><td>MECHANISM</td><td>bottom (enters block)</td><td>M</td></tr><tr><td>CALL</td><td>bottom (exits block)</td><td>R</td></tr></tbody></table><h2 id="journal-app" tabindex="-1">Journal app <a class="header-anchor" href="#journal-app" aria-label="Permalink to &quot;Journal app&quot;">​</a></h2><h3 id="key-paths-1" tabindex="-1">Key paths <a class="header-anchor" href="#key-paths-1" aria-label="Permalink to &quot;Key paths&quot;">​</a></h3><ul><li><code>crypto.js</code> — SHARED substrate; reused by any future module (planner, decision-journal, etc.)</li><li><code>Journal/vault.js</code> — pure data model and logic</li><li><code>Journal/db.js</code> — IndexedDB persistence (envelope only, no plaintext)</li><li><code>Journal/exporter.js</code> — encrypted file export/import</li><li><code>Journal.vue</code> — full UI (unlock, editor, progress, past entries, sync)</li></ul><h3 id="journal-modules" tabindex="-1">Journal modules <a class="header-anchor" href="#journal-modules" aria-label="Permalink to &quot;Journal modules&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>components/crypto.js</code></td><td><code>randomBytes</code>, <code>deriveKey</code> (PBKDF2-SHA-256 → AES-GCM 256), <code>encryptJSON</code>/<code>decryptJSON</code>, <code>packEnvelope</code>/<code>unpackEnvelope</code> (base64 at-rest format)</td></tr><tr><td><code>Journal/vault.js</code></td><td><code>emptyVault</code>, <code>upsertEntry</code>, <code>countWords</code>, <code>goalMet</code>, <code>computeStreak</code>, <code>mergeVaults</code> (per-date LWW by <code>updatedAt</code>)</td></tr><tr><td><code>Journal/db.js</code></td><td>IndexedDB open/save/load for a single packed envelope string; debounced save 300 ms; cross-tab sync via localStorage</td></tr><tr><td><code>Journal/exporter.js</code></td><td><code>exportEnvelope</code> → download <code>.journal</code> file; <code>readEnvelopeFile</code> → string</td></tr></tbody></table><h3 id="crypto-model" tabindex="-1">Crypto model <a class="header-anchor" href="#crypto-model" aria-label="Permalink to &quot;Crypto model&quot;">​</a></h3><ul><li>Key derivation: <code>PBKDF2(passphrase, salt=16 bytes, iterations=600000, SHA-256)</code> → AES-GCM 256</li><li>Per-encryption: <code>iv</code> = 12 random bytes; <code>salt</code> is per-vault (generated once on vault creation)</li><li>At-rest envelope: <code>{ salt, iterations, iv, ciphertext }</code> all base64-encoded — no key, no plaintext ever persisted</li><li>Key lives only in memory for the session; re-derived on unlock</li></ul><h3 id="vault-shape" tabindex="-1">Vault shape <a class="header-anchor" href="#vault-shape" aria-label="Permalink to &quot;Vault shape&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{ version, createdAt, entries: { &quot;YYYY-MM-DD&quot;: { text, words, createdAt, updatedAt } } }</span></span></code></pre></div><h3 id="merge-single-user-lww" tabindex="-1">Merge (single-user LWW) <a class="header-anchor" href="#merge-single-user-lww" aria-label="Permalink to &quot;Merge (single-user LWW)&quot;">​</a></h3><p>Union of dates; for a shared date keep the entry with the greater <code>updatedAt</code>. Deterministic, idempotent, commutative — safe for file sync, no CRDT needed.</p><h3 id="streak" tabindex="-1">Streak <a class="header-anchor" href="#streak" aria-label="Permalink to &quot;Streak&quot;">​</a></h3><p>Walk back from today; a day counts if <code>goalMet</code> (≥ 500 words); first miss ends the streak. Today&#39;s in-progress entry does not break a prior streak until the day rolls over.</p><h3 id="sync" tabindex="-1">Sync <a class="header-anchor" href="#sync" aria-label="Permalink to &quot;Sync&quot;">​</a></h3><ul><li>v1 (implemented): encrypted file export/import — Export downloads a <code>.journal</code> envelope; Import reads it, decrypts with current key (or prompts separately), merges with LWW, saves</li><li>Cross-tab sync: localStorage event triggers re-load + merge on other open tabs</li></ul><h3 id="reusable-vault-substrate" tabindex="-1">Reusable vault substrate <a class="header-anchor" href="#reusable-vault-substrate" aria-label="Permalink to &quot;Reusable vault substrate&quot;">​</a></h3><p><code>components/crypto.js</code> + <code>Journal/vault.js</code> + <code>Journal/db.js</code> are designed for reuse. Future modules (planner, decision-journal, habit tracker) import the same crypto.js and can define their own vault shape and db.js variant without any shared-code changes.</p><h3 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h3><p>Unit tests run with <code>node --test</code> (Node 22, native <code>crypto.subtle</code>):</p><ul><li><code>crypto.test.mjs</code> — derive→encrypt→decrypt round-trip; wrong passphrase rejects; envelope pack/unpack; large-buffer base64 (byte-loop, no spread-overflow)</li><li><code>Journal/vault.test.mjs</code> — <code>countWords</code>, <code>upsertEntry</code>, <code>computeStreak</code>, <code>mergeVaults</code></li><li><code>Journal/exporter.test.mjs</code> — encrypt→pack→unpack→decrypt→merge round-trip; tampered ciphertext rejects</li></ul><h2 id="piano-teacher-app" tabindex="-1">Piano Teacher app <a class="header-anchor" href="#piano-teacher-app" aria-label="Permalink to &quot;Piano Teacher app&quot;">​</a></h2><h3 id="piano-modules" tabindex="-1">Piano modules <a class="header-anchor" href="#piano-modules" aria-label="Permalink to &quot;Piano modules&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Piano/midi.js</code></td><td><code>useMidi()</code> composable: <code>requestMIDIAccess</code>, reactive <code>pressedNotes</code> Set, <code>deviceName</code>, <code>status</code></td></tr><tr><td><code>Piano/score.js</code></td><td>Score JSON CRUD, built-in pieces, <code>getScaleKeys(key)</code>, <code>getNonScaleKeys()</code>, <code>getActiveKey(score, phraseIdx, measureIdx)</code></td></tr><tr><td><code>Piano/trainer.js</code></td><td><code>createLevel1State</code> / <code>createLevel2State</code>; <code>checkNote()</code> / <code>repeatSection()</code> generic dispatchers; <code>getCurrentNote()</code>; L1 repeats measure, L2 repeats phrase</td></tr><tr><td><code>Piano/renderer.js</code></td><td>VexFlow wrapper: <code>renderPhrase(container, phrase, cursor)</code>, highlight, look-ahead, wrong-note flash</td></tr><tr><td><code>Piano/keyboard.js</code></td><td>SVG 88-key piano: <code>generateKeyRects()</code>, <code>keyColor()</code>, <code>buildKeyLayout()</code></td></tr><tr><td><code>Piano/db.js</code></td><td>IndexedDB database <code>piano</code>, object store <code>progress</code>: <code>loadProgress(scoreId)</code>, <code>saveProgress(scoreId, state)</code>, debounce 300 ms</td></tr></tbody></table><h3 id="piano-bundle-notes" tabindex="-1">Piano bundle notes <a class="header-anchor" href="#piano-bundle-notes" aria-label="Permalink to &quot;Piano bundle notes&quot;">​</a></h3><ul><li><code>Piano.vue</code> is registered as <code>defineAsyncComponent</code> — VexFlow loads only on <code>/piano</code></li><li>VexFlow is isolated via <code>manualChunks</code> in <code>config.mts</code> → separate <code>vexflow.[hash].js</code> chunk (~677 KB gzip)</li><li>Firefox: Web MIDI requires <code>dom.webmidi.enabled</code> flag; Safari: unsupported natively</li></ul><h2 id="development" tabindex="-1">Development <a class="header-anchor" href="#development" aria-label="Permalink to &quot;Development&quot;">​</a></h2><ul><li>Pure-logic unit tests: <code>node --test .vitepress/theme/components/crypto.test.mjs</code> and <code>node --test .vitepress/theme/components/Journal/*.test.mjs</code></li><li>Piano unit tests: <code>node --test .vitepress/theme/components/Piano/*.test.mjs</code></li><li>DOM/IndexedDB/file UI: manual browser verification (no automated harness)</li><li>Dev server: <code>npm run dev</code> (VitePress) — <strong>use npm, not yarn</strong> (yarn is broken in this repo)</li><li>Build: <code>npm run build</code></li></ul><h2 id="key-patterns" tabindex="-1">Key patterns <a class="header-anchor" href="#key-patterns" aria-label="Permalink to &quot;Key patterns&quot;">​</a></h2><ul><li>SVG viewport: fixed <code>viewBox=&quot;0 0 1200 800&quot;</code>, zoom via CSS <code>scale(zoom)</code>, pan via <code>translate(panX, panY)</code></li><li>Blocks: <code>&lt;rect&gt;</code> white fill + 1px stroke, label centered, number in bottom-right; red stroke on validation error; <code>[+]</code> marker if decomposed</li><li>Arrows: Manhattan L-shaped routing (min 2 segments, 90° corners); internal = solid, boundary = <code>stroke-dasharray=&quot;5,5&quot;</code>; arrowhead = filled 6px triangle</li><li>Boundary arrows attach to diagram edges; ICOM code (I1/C1/O1/M1/R1) shown at edge attachment point</li><li>Double-click block → inline <code>&lt;foreignObject&gt;&lt;input&gt;</code> label editor; Enter/blur saves, Escape cancels</li><li>Ctrl+Z / Ctrl+Y → undo/redo; Hover block → ICOM handles appear for drawing arrows</li><li>Decompose: toolbar &quot;↳ Войти&quot; button navigates into child diagram; breadcrumb for navigation</li><li>Plan files live in <code>docs/plans/</code> and are git-ignored (local only)</li></ul><h2 id="completed-features" tabindex="-1">Completed features <a class="header-anchor" href="#completed-features" aria-label="Permalink to &quot;Completed features&quot;">​</a></h2><h3 id="idef0-editor-as-of-2026-06-07" tabindex="-1">IDEF0 editor (as of 2026-06-07) <a class="header-anchor" href="#idef0-editor-as-of-2026-06-07" aria-label="Permalink to &quot;IDEF0 editor (as of 2026-06-07)&quot;">​</a></h3><ul><li>Full rewrite: canvas → SVG + Vue 3, strictly following FIPS 183</li><li>Reactive model (model.js): Project / Diagram / Box / Arrow / BoundaryArrow data structures</li><li>SVG rendering: boxes, internal arrows (Manhattan routing), boundary arrows with ICOM codes</li><li>Auto-layout: FIPS 183 diagonal placement (box 1 top-left, box N bottom-right)</li><li>Block drag-and-drop; arrow routing updates on drag; click-to-select; Delete to remove</li><li>Arrow drawing: hover handles on block sides → drag to connect → ICOM type popup</li><li>Inline label editing: double-click block or arrow label</li><li>Diagram hierarchy: decompose box → child diagram with boundary arrows; breadcrumb navigation</li><li>Undo/redo (Ctrl+Z / Ctrl+Y), 50-step snapshots, resets on diagram switch</li><li>IndexedDB persistence (auto-save debounced 300 ms) + cross-tab sync via localStorage</li><li>Export: SVG, PNG (2×), JSON; Import: JSON round-trip</li><li>FIPS 183 validation panel: errors shown in sidebar, red border on offending blocks</li></ul><h3 id="journal-app-as-of-2026-06-08" tabindex="-1">Journal app (as of 2026-06-08) <a class="header-anchor" href="#journal-app-as-of-2026-06-08" aria-label="Permalink to &quot;Journal app (as of 2026-06-08)&quot;">​</a></h3><ul><li>WebCrypto substrate: PBKDF2 key derivation + AES-GCM encrypt/decrypt + base64 envelope format</li><li>Vault data model: entries by date, word count, streak, per-date LWW merge</li><li>Encrypted IndexedDB persistence: only the packed envelope is stored (no plaintext, no key)</li><li>Journal UI: unlock screen, today&#39;s textarea with live word count, 500-word progress bar, streak display, past-entries list, optional focus-lock mode</li><li>Debounced autosave: edit → upsertEntry → encryptJSON → packEnvelope → db.saveEnvelope</li><li>Cross-tab sync via localStorage events</li><li>Sync v1: encrypted file export/import (.journal files) with LWW merge on import</li><li>Unit tests for all pure logic (crypto, vault, exporter data layer)</li></ul><h3 id="piano-teacher-app-as-of-2026-06-08" tabindex="-1">Piano Teacher app (as of 2026-06-08) <a class="header-anchor" href="#piano-teacher-app-as-of-2026-06-08" aria-label="Permalink to &quot;Piano Teacher app (as of 2026-06-08)&quot;">​</a></h3><ul><li>Interactive MIDI teacher at <code>/piano</code>: Web MIDI API (no polyfill, native), VexFlow 5 via npm (no CDN)</li><li>Modules in <code>.vitepress/theme/components/Piano/</code>: <ul><li><code>midi.js</code> — <code>useMidi()</code> composable: device list, reactive pressed-notes Set, noteOn/noteOff</li><li><code>score.js</code> — Score JSON format (phrases/measures/notes), built-in pieces (C major scale, Twinkle, Minuet), <code>getScaleKeys()</code>, <code>getActiveKey()</code></li><li><code>trainer.js</code> — <code>createLevel1State</code> / <code>createLevel2State</code>; <code>checkNote()</code> / <code>repeatSection()</code> dispatchers; L1 repeats measure, L2 repeats phrase</li><li><code>renderer.js</code> — VexFlow wrapper: <code>renderPhrase()</code>, current-note highlight, look-ahead (30% opacity), wrong-note flash (400 ms red overlay)</li><li><code>keyboard.js</code> — SVG 88-key piano (A0–C8), <code>generateKeyRects()</code>, <code>keyColor()</code></li><li><code>db.js</code> — IndexedDB database <code>piano</code> / store <code>progress</code>, session stats (accuracy %, notesPlayed, longestStreak), debounced save 300 ms</li></ul></li><li>Full UI: topbar (score dropdown, level toggle, tempo slider, hand toggle), VexFlow stave, keyboard strip, metronome (4 beat dots), status bar (measure/phrase, accuracy, streak)</li><li>Piano.vue registered as <code>defineAsyncComponent</code> — VexFlow only loads on <code>/piano</code>, not bundled in shared theme chunk</li><li>VexFlow isolated in its own build chunk (<code>~677 KB gzip</code>); Piano component itself ~7 KB gzip</li><li>Firefox note: Web MIDI API requires <code>dom.webmidi.enabled</code> flag or WebMIDIAPI shim; Safari unsupported (banner shown)</li><li>Unit tests: <code>node --test .vitepress/theme/components/Piano/*.test.mjs</code></li></ul>',46)])])}const m=o(r,[["render",i]]);export{h as __pageData,m as default};
